function listOfInts(input: string): readonly number[] {
  // Validate non-ASCII characters
  for (let i = 0; i < input.length; i++) {
    if (input.charCodeAt(i) > 127) {
      throw new RangeError(`Non-ASCII character at position ${i}: code ${input.charCodeAt(i)}`);
    }
  }

  const trimmed = input.trim();

  if (!trimmed.startsWith('[')) {
    throw new SyntaxError(`Expected input to start with '[', got: ${JSON.stringify(trimmed[0])}`);
  }

  if (!trimmed.endsWith(']')) {
    throw new SyntaxError(`Expected input to end with ']'`);
  }

  const inner = trimmed.slice(1, -1).trim();

  if (inner === '') {
    return [] as const;
  }

  // Use JSON.parse to handle the parsing, then validate
  let parsed: unknown;
  try {
    parsed = JSON.parse(trimmed);
  } catch (e) {
    throw new SyntaxError(`Invalid input format: ${e instanceof Error ? e.message : String(e)}`);
  }

  if (!Array.isArray(parsed)) {
    throw new SyntaxError('Expected an array');
  }

  const result: number[] = [];
  for (let i = 0; i < parsed.length; i++) {
    const item = parsed[i];
    if (typeof item !== 'number' || !Number.isInteger(item) || item < 0) {
      throw new SyntaxError(`Element at index ${i} is not a non-negative integer: ${JSON.stringify(item)}`);
    }
    result.push(item);
  }

  return result as const;
}

export { listOfInts };
export default listOfInts;
